class LSMTree:
    def __init__(self):
        self.memtable = {}
        self.sstables = []

    def put(self, key, value):
        self.memtable[key] = value

    def get(self, key):
        if key in self.memtable:
            return self.memtable[key]
        for sstable in reversed(self.sstables):
            result = sstable.read(key)
            if result is not None:
                return result
        return None

    def flush(self):
        new_sstable = SSTable(f"sstable_{len(self.sstables)}.db")
        self.sstables.append(new_sstable)
        new_sstable.write(self.memtable)
        self.memtable = {}

class SSTable:
    def __init__(self, filename):
        self.filename = filename
        self.data = {}

    def write(self, data_dict):
        self.data = data_dict

    def read(self, key):
        return self.data.get(key)

